class CustomFlowDelegate extends FlowDelegate {
  @override
  void paintChildren(FlowPaintingContext context) {
    for (int i = 0; i < context.childCount; i++) {
      context.paintChild(
        i,
        transform: Matrix4.translationValues(i * 30.0, i * 15.0, 0),
      );
    }
  }
  @override
  bool shouldRepaint(FlowDelegate oldDelegate) => false;
}
